#[cfg(test)]
mod boot_contract_tests {
    #[test]
    fn riscv_trap_vector_saves_t0_before_reusing_it() {
        let asm = include_str!("../boot/riscv64.S");
        let save_t0 = asm
            .find("sd x5, 5 * 8(sp)")
            .expect("riscv trap vector must save x5/t0");
        let read_sscratch = asm
            .find("csrr t0, sscratch")
            .expect("riscv trap vector reads sscratch through t0");

        assert!(
            save_t0 < read_sscratch,
            "x5/t0 must be saved before the trap vector reuses it for sscratch"
        );
    }

    /// LoongArch software TLB-refill is GRADED code reachable by NO Rust handler:
    /// a refill loop never enters loongarch_trap_handler/handle_user_trap, so
    /// NEITHER the per-group wall deadline NOR the budget-timer charge can fire.
    /// programming TLBREHI.PS=0 installs a 1-byte page and re-faults forever.
    /// This test pins the LA refill handler so a regression to PS=0 fails
    /// cargo test instead of silently re-opening the infinite-refill hazard.
    #[test]
    fn loongarch_tlb_refill_sets_nonzero_page_size() {
        let asm = include_str!("../boot/loongarch64.S");
        let normalized: String = asm.chars().filter(|c| !c.is_whitespace()).collect();
        assert!(
            normalized.contains("ori$t1,$t1,12"),
            "loongarch TLB-refill must set TLBREHI.PS=12 (4 KiB) before tlbfill; PS=0 re-faults forever"
        );
        assert!(
            normalized.contains("csrwr$t1,0x8e"),
            "loongarch TLB-refill must write TLBREHI (csr 0x8e) with the PS-set value"
        );
        assert!(
            normalized.contains("tlbfill"),
            "loongarch TLB-refill must complete with tlbfill"
        );
    }
}

#[cfg(test)]
mod no_hang_contract_tests {
    #[test]
    fn riscv_user_frames_keep_supervisor_interrupts_masked() {
        let riscv = include_str!("arch/riscv64.rs");

        assert!(
            !riscv.contains("| SSTATUS_SIE | SSTATUS_SPIE"),
            "riscv user frames must not enable supervisor interrupts before sret"
        );
        assert!(
            riscv.contains("& !(SSTATUS_SPP | SSTATUS_SIE)"),
            "riscv user frames must explicitly clear SIE while preparing user mode"
        );
        assert!(
            riscv.contains("& !(SSTATUS_SIE | SSTATUS_SPIE)"),
            "riscv kernel-return frames must keep S-mode interrupts masked until Rust disables the user timer"
        );
    }

    #[test]
    fn loongarch_user_timer_does_not_enable_kernel_interrupts_early() {
        let loongarch = include_str!("arch/loongarch64.rs");
        let main_rs = include_str!("main.rs");

        assert!(
            !loongarch.contains("write_csr(CSR_CRMD, read_csr(CSR_CRMD) | CRMD_IE);"),
            "loongarch timer setup must not enable kernel interrupts before ertn"
        );
        assert!(
            loongarch.contains("frame.prmd &= !(PRMD_PPLV_MASK | PRMD_PIE);"),
            "loongarch kernel-return frames must keep interrupts masked until Rust disables the user timer"
        );
        assert!(
            loongarch.contains("&& frame.previous_privilege_is_user()"),
            "loongarch user budget timers must reject kernel-origin timer interrupts"
        );
        assert!(
            loongarch.contains("pub fn is_budget_timer_interrupt(frame: &TrapFrame) -> bool"),
            "loongarch must expose raw timer detection so kernel-origin timers can be acknowledged without killing the user context"
        );
        assert!(
            main_rs.contains("if arch::is_budget_timer_interrupt(frame)"),
            "raw timer interrupts must be handled before the generic user trap path"
        );
    }

    #[test]
    fn uart_output_waits_are_bounded() {
        for source in [
            include_str!("arch/loongarch64.rs"),
            include_str!("arch/riscv64.rs"),
        ] {
            assert!(
                source.contains("UART_PUTCHAR_SPINS"),
                "architecture putchar must have a software spin bound"
            );
            assert!(
                !source.contains("while unsafe { mmio::read8(UART0 + UART_LSR) }"),
                "architecture putchar must not wait on UART forever"
            );
        }
    }

    /// The depth-bound *semantics* (reject at depth >= limit, limit value) are
    /// now real behavior tests in `script_runtime::nesting`. This test is the
    /// thin wiring check that can only be done from source: that `main.rs`
    /// actually routes its nested-script guards through that host-tested
    /// predicate rather than an inline comparison, and still advances depth on
    /// each nested call. (Phase 5: replaced a brittle `matches(...).count() >= 3`
    /// source assertion that locked the copy-pasted inline checks in place.)
    #[test]
    fn nested_script_execution_uses_shared_depth_guard() {
        let main_rs = include_str!("main.rs");

        assert!(
            main_rs.contains("nesting_depth_exhausted(script_depth)"),
            "nested-script rejection must use the host-tested depth guard"
        );
        assert!(
            main_rs.contains("script_depth + 1"),
            "nested script calls must advance the recursion depth"
        );
    }

    #[test]
    fn process_snapshots_cover_iozone_throughput_heap_window() {
        let main_rs = include_str!("main.rs");

        assert!(
            main_rs.contains("const PROCESS_MEMORY_SLOTS: usize = 2;"),
            "the RISC-V official 256M QEMU gate only has room for a parent baseline plus one child working image"
        );
        assert!(
            main_rs.contains("PROCESS_STACK_SNAPSHOTS: [StackSnapshot; PROCESS_LIMIT]"),
            "each runtime process still needs its own child snapshot over the shared working image"
        );
        assert!(
            main_rs.contains("snapshots[child].write_i32("),
            "CLONE_CHILD_SETTID must update the child snapshot before the child is restored"
        );
        assert!(
            main_rs.contains("memories[1].copy_from(memory);"),
            "the shared child working image must be initialized before the first timer restore overlays per-child snapshots"
        );
    }

    #[test]
    fn busybox_real_shell_has_process_slots_for_nested_three_stage_pipeline() {
        let main_rs = include_str!("main.rs");

