use crate::paging::{MapError, PAGE_SIZE};

// ---------------------------------------------------------------------------
// Prot — abstract page permissions (R/W/X/U), arch-independent.
// ---------------------------------------------------------------------------

#[derive(Clone, Copy, PartialEq, Eq, Debug)]
pub struct Prot(pub u8);

impl Prot {
    pub const R: Prot = Prot(1);
    pub const W: Prot = Prot(2);
    pub const X: Prot = Prot(4);
    pub const U: Prot = Prot(8);

    pub const fn empty() -> Prot {
        Prot(0)
    }
    pub const fn union(self, o: Prot) -> Prot {
        Prot(self.0 | o.0)
    }
    pub const fn contains(self, o: Prot) -> bool {
        self.0 & o.0 == o.0
    }
    pub const fn readable(self) -> bool {
        self.contains(Prot::R)
    }
    pub const fn writable(self) -> bool {
        self.contains(Prot::W)
    }
    pub const fn executable(self) -> bool {
        self.contains(Prot::X)
    }
}

// ---------------------------------------------------------------------------
// Per-frame refcount — pure functions (host-tested), keyed by frame index.
// The substrate for BOTH COW (incref on fork-share, copy-on-write-fault) and
// the page cache (shared file-page frames). Mirrors paging.rs bump_fill style.
// ---------------------------------------------------------------------------

#[inline]
pub fn frame_index(pool_base: usize, pa: usize) -> usize {
    (pa - pool_base) / PAGE_SIZE
}

/// A freshly-allocated frame: set its refcount to 1.
pub fn ref_set_one(refcount: &mut [u16], idx: usize) {
    refcount[idx] = 1;
}

/// Share one more reference (COW fork / page-cache share).
pub fn ref_inc(refcount: &mut [u16], idx: usize) {
    refcount[idx] = refcount[idx].saturating_add(1);
}

/// Drop one reference; returns true when it hits 0 (the caller should then free
/// the frame back to the `FrameFreeList`).
pub fn ref_dec(refcount: &mut [u16], idx: usize) -> bool {
    if refcount[idx] > 0 {
        refcount[idx] -= 1;
    }
    refcount[idx] == 0
}

