use crate::scoring::{END_PREFIX, MARKER_SUFFIX, START_PREFIX};

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct ScriptMarkers<'a> {
    pub start: Option<&'a str>,
    pub end: Option<&'a str>,
}

pub fn extract_markers(text: &str) -> ScriptMarkers<'_> {
    let mut start = None;
    let mut end = None;

    for raw in text.lines() {
        let Some(line) = marker_payload(raw) else {
            continue;
        };
        if start.is_none() && is_marker(line, START_PREFIX) {
            start = Some(line);
        }
        if end.is_none() && is_marker(line, END_PREFIX) {
            end = Some(line);
        }
        if start.is_some() && end.is_some() {
            break;
        }
    }

    ScriptMarkers { start, end }
}

